---

## Common Issues and Fixes

| Problem | Likely Cause | Fix |
|---|---|---|
| `redirect_uri mismatch` | URI not registered with provider | Add exact URI to your provider's allowed redirect list |
| `invalid_grant` error | Code verifier mismatch or expired code | Regenerate verifier; use code within 60 seconds |
| State mismatch warning | Multiple tabs or back-button navigation | Restart the login flow from the login page |
| Tokens not persisting | `sessionStorage` cleared on tab close | Switch to `localStorage` with XSS risk in mind |

---

## Next Steps

Now that your base OAuth2 flow is working, consider these improvements:

- **Token refresh:** Implement silent token renewal using the `refresh_token` before expiry
- **Logout endpoint:** Call your provider's logout endpoint to invalidate the session server-side
- **HTTP interceptors:** Use Axios interceptors to attach the `access_token` automatically to API requests
- **Error boundaries:** Wrap the callback page in an error boundary for more graceful failure handling

# React Auth Context Provider for Next.js

## Overview

This implementation handles:
- **Hydration mismatch prevention** using a mounted state pattern
- **localStorage persistence** with SSR safety checks
- **TypeScript** for full type safety
- **Token validation** and auto-logout on expiry

---

## File Structure

```
src/
├── contexts/
│   └── AuthContext.tsx
├── hooks/
│   └── useAuth.ts
├── components/
│   └── AuthProvider.tsx
├── types/
│   └── auth.ts
└── utils/
    └── authUtils.ts
```

---

## Types Definition

```typescript
// src/types/auth.ts

export interface User {
  id: string;
  email: string;
  name: string;
  role: "admin" | "user" | "guest";
  avatarUrl?: string;
}

export interface AuthTokens {
  accessToken: string;
  refreshToken: string;
  expiresAt: number; // Unix timestamp in milliseconds
}

export interface AuthState {
  user: User | null;
  tokens: AuthTokens | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  isMounted: boolean; // Tracks client-side hydration
}

export interface AuthContextValue extends AuthState {
  login: (credentials: LoginCredentials) => Promise<void>;
  logout: () => void;
  updateUser: (updates: Partial<User>) => void;
  refreshTokens: () => Promise<boolean>;
}

export interface LoginCredentials {
  email: string;
  password: string;
}

export interface StoredAuthData {
  user: User;
  tokens: AuthTokens;
}
```

---

## Auth Utilities

```typescript
// src/utils/authUtils.ts

import { StoredAuthData, AuthTokens } from "@/types/auth";

const AUTH_STORAGE_KEY = "auth_data";

/**
 * Safely reads from localStorage, returning null on failure.
 * Guards against SSR environments where localStorage is undefined.
 */
export function getStoredAuthData(): StoredAuthData | null {
  // Guard: localStorage is not available in SSR/Node environments
  if (typeof window === "undefined") return null;

  try {
    const raw = localStorage.getItem(AUTH_STORAGE_KEY);
    if (!raw) return null;

    const parsed: StoredAuthData = JSON.parse(raw);

    // Validate the parsed data has the expected shape
    if (!parsed?.user?.id || !parsed?.tokens?.accessToken) {
      localStorage.removeItem(AUTH_STORAGE_KEY);
      return null;
    }

    return parsed;
  } catch {
    // Corrupted data — clear it and start fresh
    localStorage.removeItem(AUTH_STORAGE_KEY);
    return null;
  }
}

/**
 * Persists auth data to localStorage safely.
 */
export function setStoredAuthData(data: StoredAuthData): void {
  if (typeof window === "undefined") return;

  try {
    localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(data));
  } catch (error) {
    // Handle storage quota exceeded or private browsing restrictions
    console.error("[Auth] Failed to persist auth data:", error);
  }
}

/**
 * Removes auth data from localStorage.
 */
export function clearStoredAuthData(): void {
  if (typeof window === "undefined") return;
  localStorage.removeItem(AUTH_STORAGE_KEY);
}

/**
 * Checks whether the access token has expired.
 * Adds a 30-second buffer to account for clock skew.
 */
export function isTokenExpired(tokens: AuthTokens): boolean {
  const BUFFER_MS = 30_000; // 30 seconds
  return Date.now() >= tokens.expiresAt - BUFFER_MS;
}

/**
 * Decodes JWT payload without verifying signature.
 * Verification must always happen on the server.
 */
export function decodeJwtPayload(token: string): Record<string, unknown> | null {
  try {
    const [, payloadBase64] = token.split(".");
    const decoded = atob(payloadBase64.replace(/-/g, "+").replace(/_/g, "/"));
    return JSON.parse(decoded);
  } catch {
    return null;
  }
}
```

