## Auth Context

```typescript
// src/contexts/AuthContext.tsx

"use client";

import {
  createContext,
  useContext,
  useReducer,
  useEffect,
  useCallback,
  useRef,
  ReactNode,
} from "react";
import {
  AuthState,
  AuthContextValue,
  User,
  LoginCredentials,
  AuthTokens,
} from "@/types/auth";
import {
  getStoredAuthData,
  setStoredAuthData,
  clearStoredAuthData,
  isTokenExpired,
} from "@/utils/authUtils";

// ─── Initial State ────────────────────────────────────────────────────────────

/**
 * CRITICAL: Initial state must match what the server renders.
 * All auth state starts as "unauthenticated" to prevent hydration mismatches.
 * Actual auth state is loaded client-side after mount via useEffect.
 */
const INITIAL_STATE: AuthState = {
  user: null,
  tokens: null,
  isAuthenticated: false,
  isLoading: true,  // true = still checking localStorage
  isMounted: false, // false until client hydration completes
};

// ─── Reducer ──────────────────────────────────────────────────────────────────

type AuthAction =
  | { type: "HYDRATE"; payload: { user: User; tokens: AuthTokens } | null }
  | { type: "LOGIN_SUCCESS"; payload: { user: User; tokens: AuthTokens } }
  | { type: "LOGOUT" }
  | { type: "UPDATE_USER"; payload: Partial<User> }
  | { type: "REFRESH_TOKENS"; payload: AuthTokens }
  | { type: "SET_LOADING"; payload: boolean };

function authReducer(state: AuthState, action: AuthAction): AuthState {
  switch (action.type) {
    case "HYDRATE":
      // Called once after mount to restore persisted session
      return {
        ...state,
        user: action.payload?.user ?? null,
        tokens: action.payload?.tokens ?? null,
        isAuthenticated: !!action.payload?.user,
        isLoading: false,
        isMounted: true, // Mark as hydrated — UI can now render auth-aware content
      };

    case "LOGIN_SUCCESS":
      return {
        ...state,
        user: action.payload.user,
        tokens: action.payload.tokens,
        isAuthenticated: true,
        isLoading: false,
      };

    case "LOGOUT":
      return {
        ...state,
        user: null,
        tokens: null,
        isAuthenticated: false,
        isLoading: false,
      };

    case "UPDATE_USER":
      if (!state.user) return state;
      return {
        ...state,
        user: { ...state.user, ...action.payload },
      };

    case "REFRESH_TOKENS":
      return {
        ...state,
        tokens: action.payload,
      };

    case "SET_LOADING":
      return { ...state, isLoading: action.payload };

    default:
      return state;
  }
}

// ─── Context ──────────────────────────────────────────────────────────────────

const AuthContext = createContext<AuthContextValue | null>(null);

// ─── Provider ─────────────────────────────────────────────────────────────────

interface AuthProviderProps {
  children: ReactNode;
}

export function AuthProvider({ children }: AuthProviderProps) {
  const [state, dispatch] = useReducer(authReducer, INITIAL_STATE);

  // Ref to track the token refresh timer for cleanup
  const refreshTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // ─── Hydration Effect ─────────────────────────────────────────────────────

  useEffect(() => {
    /**
     * This runs ONLY on the client after initial render.
     * By dispatching HYDRATE here, we avoid hydration mismatches because:
     * 1. Server renders with INITIAL_STATE (no auth)
     * 2. Client renders first pass with same INITIAL_STATE
     * 3. After hydration matches, we update state with localStorage data
     */
    const storedData = getStoredAuthData();

    if (storedData && !isTokenExpired(storedData.tokens)) {
      dispatch({ type: "HYDRATE", payload: storedData });
    } else {
      // No valid session found — clear any stale data
      clearStoredAuthData();
      dispatch({ type: "HYDRATE", payload: null });
    }
  }, []); // Empty deps: runs once after mount

  // ─── Token Refresh Scheduler ───────────────────────────────────────────────

  useEffect(() => {
    if (!state.tokens || !state.isAuthenticated) return;

    const scheduleRefresh = () => {
      const timeUntilExpiry = state.tokens!.expiresAt - Date.now();
      // Refresh 60 seconds before expiry to ensure seamless experience
      const refreshDelay = Math.max(timeUntilExpiry - 60_000, 0);

      refreshTimerRef.current = setTimeout(async () => {
        const success = await refreshTokens();
        if (!success) {
          // Refresh failed — force logout to protect security
          logout();
        }
      }, refreshDelay);
    };

    scheduleRefresh();

    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [state.tokens?.expiresAt, state.isAuthenticated]);

  // ─── Auth Actions ──────────────────────────────────────────────────────────

  const login = useCallback(async (credentials: LoginCredentials) => {
    dispatch({ type: "SET_LOADING", payload: true });

    try {
      // Replace this with your actual API call
      const response = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(credentials),
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message ?? "Login failed");
      }

      const { user, tokens } = await response.json();

      // Persist before dispatching so data is available on next render
      setStoredAuthData({ user, tokens });
      dispatch({ type: "LOGIN_SUCCESS", payload: { user, tokens } });
    } catch (error) {
      dispatch({ type: "SET_LOADING", payload: false });
      throw error; // Re-throw so calling component can handle UI feedback
    }
  }, []);

  const logout = useCallback(() => {
    // Clear refresh timer immediately
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    clearStoredAuthData();
    dispatch({ type: "LOGOUT" });

    // Optionally notify the server to invalidate the refresh token
    fetch("/api/auth/logout", { method: "POST" }).catch(() => {
      // Fire-and-forget — local logout always succeeds
    });
  }, []);

  const updateUser = useCallback(
    (updates: Partial<User>) => {
      if (!state.user) return;

      const updatedUser = { ...state.user, ...updates };

      // Keep localStorage in sync with state updates
      if (state.tokens) {
        setStoredAuthData({ user: updatedUser, tokens: state.tokens });
      }

      dispatch({ type: "UPDATE_USER", payload: updates });
    },
    [state.user, state.tokens]
  );

  const refreshTokens = useCallback(async (): Promise<boolean> => {
    if (!state.tokens?.refreshToken) return false;

    try {
      const response = await fetch("/api/auth/refresh", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ refreshToken: state.tokens.refreshToken }),
      });

      if (!response.ok) return false;

      const newTokens: AuthTokens = await response.json();

      if (state.user) {
        setStoredAuthData({ user: state.user, tokens: newTokens });
      }

      dispatch({ type: "REFRESH_TOKENS", payload: newTokens });
      return true;
    } catch {
      return false;
    }
  }, [state.tokens, state.user]);

  // ─── Context Value ─────────────────────────────────────────────────────────

  const contextValue: AuthContextValue = {
    ...state,
    login,
    logout,
    updateUser,
    refreshTokens,
  };

  return (
    <AuthContext.Provider value={contextValue}>
      {children}
    </AuthContext.Provider>
  );
}

// ─── Context Export ────────────────────────────────────────────────────────────

export { AuthContext };
```

