## Custom Hook

```typescript
// src/hooks/useAuth.ts

"use client";

import { useContext } from "react";
import { AuthContext } from "@/contexts/AuthContext";
import { AuthContextValue } from "@/types/auth";

/**
 * Primary hook for accessing auth state and actions.
 *
 * @throws {Error} When used outside of <AuthProvider>
 *
 * @example
 * const { user, isAuthenticated, login, logout } = useAuth();
 */
export function useAuth(): AuthContextValue {
  const context = useContext(AuthContext);

  if (!context) {
    throw new Error(
      "[useAuth] Must be used within an <AuthProvider>. " +
      "Ensure your component tree is wrapped with <AuthProvider>."
    );
  }

  return context;
}

/**
 * Hook that returns only the current user, memoized for performance.
 * Useful for components that only need to read user data.
 */
export function useCurrentUser() {
  const { user, isAuthenticated, isMounted } = useAuth();
  return { user, isAuthenticated, isMounted };
}

/**
 * Hook that returns auth actions only, without subscribing to state changes.
 * Prevents re-renders in components that only call auth methods.
 */
export function useAuthActions() {
  const { login, logout, updateUser, refreshTokens } = useAuth();
  return { login, logout, updateUser, refreshTokens };
