"use client";

import { ReactNode } from "react";
import { useAuth } from "@/hooks/useAuth";

interface AuthGuardProps {
  children: ReactNode;
  fallback?: ReactNode;         // Shown when logged out
  loadingFallback?: ReactNode;  // Shown during hydration
}

/**
 * Renders children only when authenticated.
 * Shows loadingFallback during SSR and initial hydration to prevent flicker.
 *
 * Pattern: Always render something consistent during isMounted=false
 * to avoid hydration mismatches.
 */
export function AuthGuard({
  children,
  fallback = null,
  loadingFallback = null,
}: AuthGuardProps) {
  const { isAuthenticated, isLoading, isMounted } = useAuth();

  // HYDRATION SAFETY: Before client-side mount, render the loading state.
  // This matches what the server rendered (which also has no auth state).
  if (!isMounted || isLoading) {
    return <>{loadingFallback}</>;
  }

  return isAuthenticated ? <>{children}</> : <>{fallback}</>;
}

